var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MIYA_HB_ReinforcedA_NULL","text":{"KOREA":"에헤헤, 오늘은 사장님께서 아주 중요한 얘기가 있으시다나 봐요...... 시청자 여러분, 보고 계시죠?","JPN":"えへへ、今日は社長から、とても大事な話があるんだそうです……視聴者の皆さん、見てますか？","ENG":"Heh heh. It seems today, my boss has something important to say to me. Guys, you're watching this, right?","TWN":"嘿嘿，看來今天老闆似乎有非常重要的事情……各位觀眾朋友們，大家有在看嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MIYA_HB_ReinforcedA_NULL","text":{"KOREA":"어? 카, 카메라가 꺼져 있었네?","JPN":"あれ？　カ、カメラの電源が落ちてる。","ENG":"Err? Th-the camera isn't on.","TWN":"嗯？攝，攝影機怎麼是關著的？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MIYA_HB_ReinforcedA_NULL","text":{"KOREA":"후으으... 어쩌지... 또 사과문을 써야 할 텐데......","JPN":"はうぅ……ど、どうしよう……また謝罪文を書かなくちゃ……","ENG":"Aww... No... I have to write yet another letter of apology...","TWN":"嗚嗚……怎麼辦……又得寫道歉文了……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_ReinforcedA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MIYA_HB_ReinforcedA_NULL","text":{"KOREA":"좋았어. 이번엔 색다르게 자몽문으로......","JPN":"こ、こうなったら、今度の配信は反省会スペシャルということにして……","ENG":"Alright, this time I'm going to use the Grapefruit font...","TWN":"好吧，這次就來點新鮮的，寫個菜英文……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MIYA_HB_ReinforcedA_NULL","text":{"KOREA":"앗, 사장님... 미, 미하~","JPN":"あっ、社長……！　ミ、ミハー……","ENG":"Ah, Boss! H-hello!","TWN":"啊，老闆……米、米哈～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MIYA_HB_ReinforcedA_NULL","text":{"KOREA":"네? 종신계약이요......?","JPN":"はい？　終身契約……ですか……？","ENG":"Pardon? A lifetime contract?","TWN":"咦？終身契約……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MIYA_HB_ReinforcedA_NULL","text":{"KOREA":"아, 저... 그치만 저는요, 굼뜨고...... 유머 센스도 없어서...... 가은이나, 루미나, 보미한테 언제나 도움만 받는걸요......","JPN":"あっ、でも……ミヤは……ノロマですし、ユーモアのセンスもないですし……ユキや、ルミや、ボミたちに助けられてばかりで……","ENG":"Ah, erm... But I'm not quick... or funny... Gaeun, Lumi, and Bomi have to help me all the time...","TWN":"啊，那個……可是我……又遲鈍……又沒有幽默感……而且還一直單方面受到嘉恩、魯米和普美的照顧……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_ReinforcedA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MIYA_HB_ReinforcedA_NULL","text":{"KOREA":"그런 점을 바꾸고 싶어서 방송을 시작한 건데, 잘하고 있는지 항상 걱정돼요......","JPN":"そんな自分を変えたくて配信を始めたんですけど、ちゃんとできてるのか、いつも心配なんです……","ENG":"I started broadcasting to change myself, but I don't know if I'm doing it right or not.","TWN":"為了改變這一點，我才開始直播，但是很常擔心自己有不有做好……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_ReinforcedA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MIYA_HB_ReinforcedA_NULL","text":{"KOREA":"사장님이 보시기에는...... 어떤 것 같아요? 미야는...... 저는 잘하고 있는 걸까요......?","JPN":"社長……社長は、どう……思われますか？\\n……ミヤは……ちゃんとやれてるんでしょうか……？","ENG":"What do you think, Boss? Am I doing it right?","TWN":"老闆您覺得……怎麼樣？米婭……我做得好嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};